INSERT INTO areas (id, data, updated_at)
SELECT (value->>'id')::text, value, now()
FROM jsonb_array_elements('[{"id":"meonstoke-so32","name":"Meonstoke","village":"Meonstoke","town":"Southampton","county":"Hampshire","postcode":"SO32","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Southampton","coords":{"lat":50.9548,"lng":-1.2036},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"micheldever-so21","name":"Micheldever","village":"Micheldever","town":"Winchester","county":"Hampshire","postcode":"SO21","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Winchester","coords":{"lat":51.06068,"lng":-1.29512},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":{"avgDetached":1058605,"avgSemi":541803,"avgTerraced":488613,"avgFlat":null,"asOf":"2026-05"},"councilTaxBand":"D","overview":"Micheldever is a picture-postcard chalk village and civil parish of around 1,387 residents at the 2011 Census, set on the small River Dever six miles north of Winchester in the City of Winchester district. The parish is one of the most northerly in the district and includes the separate village of Micheldever Station (around 2.4 miles north of the village proper), East and West Stratton, Weston Colley and the hamlet of Woodmancott. The village core, around Duke Street, Church Street and the small green known as The Crease, is famous for its black-and-white half-timbered cottages and the Norman St Mary the Virgin church; the oldest house, Shillingbury, dates to circa 1453. The Half Moon and Spread Eagle pub, originally a drovers'' inn at the edge of the village, has been a fixture since the eighteenth century. Micheldever station, opened in 1840 as ''Andover Road'', sits two miles up the lane and gives direct South Western Railway trains to London Waterloo.","character":"Genuine timber-framed conservation-area village — one of the prettiest in the Itchen catchment — with a tight nucleated core around the church, the green and the pub. Building stock is mostly Tudor and Georgian thatched cottages, a few Victorian additions and very limited modern infill; planning is tightly constrained inside the conservation area.","amenities":["Half Moon and Spread Eagle pub (Duke Street)","St Mary the Virgin Church (Church of England, Norman)","Micheldever CofE Primary School (within village)","Northbrook village hall","The Crease — small green at the centre of the village","Micheldever telephone exchange","Micheldever railway station (2.4 mi — Andover-line direct service)","Micheldever Tyre Services (commercial site at the station)","Nearest supermarket and full retail: Winchester (6 mi)"],"schools":[{"name":"Micheldever CofE Primary School","phase":"Primary","type":"State (Voluntary Controlled, Dever Valley Federation)","ofsted":"Good (2022)","distance":"in village","url":"https://reports.ofsted.gov.uk/provider/21/133292"},{"name":"Henry Beaufort School (catchment)","phase":"Secondary","type":"State (Comprehensive)","ofsted":"Good (2023)","distance":"5.0 mi","url":"https://reports.ofsted.gov.uk/provider/21/116438"},{"name":"Peter Symonds College (16-18)","phase":"Sixth Form","type":"State (Sixth-form college)","ofsted":"Outstanding (2019)","distance":"5.5 mi","url":"https://reports.ofsted.gov.uk/provider/22/130688"}],"transport":{"commutes":[{"to":"London Waterloo","time":"1h 13m (direct, 1 train/hour)","mode":"drive 2.4 mi to Micheldever station + direct train (SWR)","source":"https://en.wikipedia.org/wiki/Micheldever_railway_station"},{"to":"Winchester","time":"12m","mode":"direct train from Micheldever (SWR)","source":"https://www.thetrainline.com/stations/micheldever"},{"to":"Basingstoke","time":"~20m","mode":"drive (A33/M3)","source":"https://www.google.com/maps"}],"nearestStation":"Micheldever (2.4 mi)","roads":"A33 (parish edge); A303 ~5 mi; M3 J9 (Winchester) ~7 mi"},"prices":{"avgSold12Mo":712724,"avgDetached":1058605,"avgSemi":541803,"avgTerraced":488613,"avgBungalow":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/so21.html","asOf":"2026-05"},"thingsToDo":["Micheldever Wood bluebell walk (William Cobbett''s ''one of the finest oak woods in England'')","Walking the River Dever and the Test Way","The Crease and Norman St Mary''s church","Bombay Sapphire Distillery, Laverstoke Mill (5 mi)","Watercress Line steam railway from Alresford (8 mi)"],"placesToEat":[{"name":"Half Moon and Spread Eagle","type":"Village pub","notes":"Eighteenth-century drovers'' inn; food and ales","url":"https://www.facebook.com/halfmoonmicheldever/"},{"name":"The Dove Inn, Micheldever Station","type":"Village pub","notes":"2 miles north at the station village","url":"https://whatpub.com/pubs/HAS/00111/dove-inn-micheldever-station"}],"pros":["Direct Waterloo trains in just over an hour from Micheldever station","Genuine conservation-area chalk-village character — Tudor and Georgian cottages","Good village primary inside walking distance and Good catchment secondary","A33 and A303 give very fast access to Winchester, Andover and Basingstoke","Active village hall, church and pub on the same street"],"cons":["Detached stock averages over £1m in SO21 — a £400k budget will buy a small terrace or semi at best, when they list","No shop or GP in the village itself — Winchester or Sutton Scotney for both","South West Main Line cuts the parish; freight trains audible on calmer evenings","Single-track lanes into the village are slow and easily blocked","Conservation-area status restricts extensions and outbuildings"],"whoItSuits":"A strong candidate for a buyer who wants the storybook Hampshire village look with a direct Waterloo train just up the lane. For a solo £64k first-time buyer at £400k, listings here are rare and small — typically a one- or two-bedroom semi or end-terrace when they appear. If timber-framed character matters most, Easton and Itchen Abbas are similar but pricier; if the same Waterloo connection at a much lower entry price matters most, look at the more workaday Micheldever Station hamlet 2 miles north (same line, same district) or Sutton Scotney.","broadbandMedianMbps":null,"nearestStation":"Micheldever (2.4 mi)","primarySupermarket":"Co-op, Sutton Scotney (4.5 mi); Sainsbury''s, Middle Brook Street, Winchester (6.0 mi)","images":[],"sources":[{"title":"Wikipedia — Micheldever","url":"https://en.wikipedia.org/wiki/Micheldever"},{"title":"Wikipedia — Micheldever railway station","url":"https://en.wikipedia.org/wiki/Micheldever_railway_station"},{"title":"Micheldever Villages — village history","url":"https://www.micheldevervillages.org/micheldever-village"},{"title":"Ofsted — Micheldever CofE Primary School","url":"https://reports.ofsted.gov.uk/provider/21/133292"},{"title":"Ofsted — Henry Beaufort School","url":"https://reports.ofsted.gov.uk/provider/21/116438"},{"title":"Rightmove — SO21 house prices","url":"https://www.rightmove.co.uk/house-prices/so21.html"}]},{"id":"michelmersh-so51","name":"Michelmersh","village":"Michelmersh","town":"Winchester","county":"Hampshire","postcode":"SO51","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Winchester","coords":{"lat":50.97212,"lng":-1.50032},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":null,"overview":"Michelmersh is a small, scattered village in the Test Valley district about three miles north of Romsey, set on high ground overlooking the River Test valley. It forms one half of the joint civil parish of Michelmersh and Timsbury, which had a combined population of 915 in 2021 across an area of about 1,128 hectares (1.80% of the borough), making it Test Valley''s twenty-second largest parish by area. The 12th-century Grade I-listed St Mary''s Church sits at the village heart, with the Monarch''s Way long-distance footpath crossing its churchyard. The Georgian former rectory, Michelmersh Court, is Grade II*-listed and was for many years the home of broadcaster Sir David Frost. The parish hosts Michelmersh Brick Holdings, the last operational brickworks in Hampshire, producing premium clay bricks from on-site materials. Michelmersh was a regular filming location for the 1980s ITV series Worzel Gummidge.","character":"Linear, scattered village of brick, brick-and-flint and tile-hung cottages along Church Road and Hartley Lane, with the brickworks site forming a distinct industrial presence to one side. The Test valley setting is broad and chalky in the north of the parish, sliding into Eocene sands and clays further south. Plenty of working farmland, no nucleated centre but a strong sense of community.","amenities":["Bear and Ragged Staff (Romsey Road, the village pub)","St Mary''s Church (Grade I, 12th-century)","Michelmersh Brickworks (working brickworks and visitor element)","Michelmersh and Timsbury Village Hall","Nearest convenience shop: Awbridge or Timsbury (1 mi)","Full retail at Romsey high street and Waitrose (3 mi)","Mottisfont Abbey gardens (National Trust, 3 mi)","Test Valley footpaths and the Monarch''s Way"],"schools":[{"name":"Awbridge Primary School","phase":"Primary","type":"State (Community)","ofsted":"Good (2023)","distance":"1.5 mi","url":"https://reports.ofsted.gov.uk/provider/21/115872"},{"name":"Braishfield Church of England Primary School","phase":"Primary","type":"State (Voluntary Controlled)","ofsted":"Good (2022)","distance":"2.3 mi","url":"https://reports.ofsted.gov.uk/provider/21/115835"},{"name":"The Romsey School","phase":"Secondary","type":"State (Academy, Comprehensive)","ofsted":"Good (2023)","distance":"3.5 mi","url":"https://reports.ofsted.gov.uk/provider/23/137094"}],"transport":{"commutes":[{"to":"London Waterloo","time":"1h 25m","mode":"drive to Romsey (3 mi) + train via Southampton Central (SWR)","source":"https://www.thetrainline.com/train-times/romsey-to-london-waterloo"},{"to":"Southampton Central","time":"~25m","mode":"drive (A3057/M27)","source":"https://www.google.com/maps"},{"to":"Winchester (by road)","time":"~25m","mode":"drive (A3090)","source":"https://www.google.com/maps"}],"nearestStation":"Mottisfont and Dunbridge (1.8 mi)","roads":"A3057 ~1 mi; A36 ~3 mi; M27 J3 ~5 mi"},"prices":{"avgSold12Mo":485894,"avgDetached":null,"avgSemi":null,"avgTerraced":null,"avgBungalow":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/so51.html","asOf":"2026-05"},"thingsToDo":["Mottisfont Abbey rose gardens (National Trust, 3 mi)","Walking the Monarch''s Way through the parish","Test Way footpath along the chalk stream","Sir Harold Hillier Gardens (3 mi)","Romsey Abbey and Saturday market (3 mi)","Broadlands House and grounds (3 mi)"],"placesToEat":[{"name":"Bear and Ragged Staff","type":"Village pub","notes":"Romsey Road, traditional country pub with food","url":"https://whatpub.com/pubs/HAS/00018/bear-and-ragged-staff-michelmersh"},{"name":"Mottisfont Abbey Kitchen","type":"National Trust café","notes":"3 miles away at Mottisfont; lunch and cakes","url":"https://www.nationaltrust.org.uk/visit/hampshire/mottisfont"}],"pros":["Genuine rural Test Valley setting with the Monarch''s Way through the village","SO51 average sold price (£485k) is the most attainable of all the buyer''s target postcodes","Mottisfont and Dunbridge station (1.8 mi) gives a quiet direct line to Romsey and Salisbury","Two Good village primaries within 2.5 miles, plus a Good comprehensive at Romsey","Mottisfont Abbey, Hillier Gardens and Romsey market town all within 5 miles"],"cons":["Scattered village means a car is essential — no walkable shop or GP cluster","Brickworks lorries periodically use the lanes","Direct Waterloo journey requires change at Southampton (1h 25m total)","Limited mobile coverage in parts of the parish","Listed and conservation considerations on much of the older stock"],"whoItSuits":"Easily the most affordable of this batch and the best fit for a solo first-time buyer at £400k who wants Test Valley countryside and Romsey/Salisbury access more than Waterloo speed — SO51 averages under £500k and terraced and semi-detached stock can land well inside budget. The Bear and Ragged Staff plus a Good primary in either Awbridge or Braishfield are real day-to-day positives. For a stronger station and cheaper still, look at Dunbridge or Lockerley (both SO51); for prettier-but-pricier with the same Test feel, Mottisfont itself or Houghton (SO20).","broadbandMedianMbps":null,"nearestStation":"Mottisfont and Dunbridge (1.8 mi)","primarySupermarket":"Waitrose, The Hundred, Romsey (3.0 mi); Co-op, Romsey (3.0 mi)","images":[],"sources":[{"title":"Wikipedia — Michelmersh","url":"https://en.wikipedia.org/wiki/Michelmersh"},{"title":"Test Valley BC — Michelmersh and Timsbury Parish Profile 2024","url":"https://testvalley.gov.uk/assets/attach/21890/Michelmersh-and-Timsbury-Profile-2024.pdf"},{"title":"Ofsted — Awbridge Primary School","url":"https://reports.ofsted.gov.uk/provider/21/115872"},{"title":"Ofsted — The Romsey School","url":"https://reports.ofsted.gov.uk/provider/23/137094"},{"title":"Rightmove — SO51 house prices","url":"https://www.rightmove.co.uk/house-prices/so51.html"},{"title":"Trainline — Romsey to London Waterloo","url":"https://www.thetrainline.com/train-times/romsey-to-london-waterloo"}]},{"id":"middle-wallop-so20","name":"Middle Wallop","village":"Middle Wallop","town":"Andover","county":"Hampshire","postcode":"SO20","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Andover","coords":{"lat":51.13144,"lng":-1.47436},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":"D","overview":"Middle Wallop is a small linear village in the Test Valley district, around six miles north-west of Stockbridge and seven miles south-west of Andover, sitting between Over Wallop and Nether Wallop along the Wallop Brook — a chalk-stream tributary of the River Test. The village is dominated by Middle Wallop Flying Station, home of the Army Air Corps and the Army Aviation Centre, with the active airfield running north-east of the A343. The Army Flying Museum (SO20 8DY), on the airfield perimeter, opened in 1974 and now holds over 35 fixed-wing and rotary aircraft including a recently-installed Apache AH Mk1 — the only example in any European museum. Visitor numbers run to tens of thousands annually. Middle Wallop was designated a Conservation Area in 2008; the village itself is small, with timber-framed cottages, farmhouses and a handful of mid-20th-century infill. The George Inn is the village pub, and the Wallops Parish Hall and a petrol station are nearby. The village''s first recorded historical association is as the supposed site of a 5th-century battle between Vitalinus (possibly Vortigern) and Ambrosius Aurelianus.","character":"Linear village along the A343, defined by the proximity of the active AAC airfield and its operational helicopter traffic. Building stock mixes 16th–19th-century cottages, RAF/AAC-era utilitarian buildings and modern infill. Conservation Area status applies.","amenities":["The George Inn (village pub)","Petrol station (A343)","Wallops Parish Hall","Army Flying Museum (Apache Café open daily)","Direct view of AAC Middle Wallop active airfield","Veterinary surgery (shared Wallops)","Shop with Post Office (in Nether Wallop)"],"schools":[{"name":"Wallop Primary School (Nether Wallop)","phase":"Primary","ofsted":"Good","distance":"1.0 mi","url":"https://files.ofsted.gov.uk/v1/file/50221039"},{"name":"The Wallops'' Pre-School","phase":"Pre-school","ofsted":null,"distance":"1.0 mi","url":"https://www.thewallopspreschool.co.uk/"},{"name":"Test Valley School / Danebury School, Stockbridge","phase":"Secondary","ofsted":"Inadequate (2022)","distance":"6.0 mi","url":"https://reports.ofsted.gov.uk/"}],"transport":{"commutes":[{"to":"London Waterloo (via Grateley)","time":"~1h 20m","mode":"drive + train (SWR West of England line)","source":"https://www.nationalrail.co.uk/"},{"to":"London Waterloo (via Andover, fastest)","time":"1h 2m","mode":"drive + train","source":"https://www.thetrainline.com/train-times/andover-to-london-waterloo"},{"to":"Salisbury","time":"~25m","mode":"drive (A343 / A30)","source":"https://www.nationalrail.co.uk/"}],"nearestStation":"Grateley (4.5 mi)","roads":"A343 (through village); A303 ~3 mi; A30 (Stockbridge) ~6 mi"},"prices":{"avgSold12Mo":null,"avgDetached":null,"avgSemi":null,"avgTerraced":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/so20.html","asOf":"2026-05"},"thingsToDo":["Army Flying Museum (over 35 historic aircraft including Apache)","Apache Café airfield-side dining (museum admission not required)","Wallop Brook Way 4.7-mile walking route","Historic Army Aircraft Flight displays at airshow events","Walking from Middle Wallop into Nether Wallop St Andrew''s church (Grade I)","Quarley High Linear earthworks (~3 mi)"],"placesToEat":[{"name":"The George Inn","type":"Village pub","notes":"Traditional pub on the A343","url":"https://www.useyourlocal.com/"},{"name":"Apache Café, Army Flying Museum","type":"Café","notes":"Airfield-side dining open daily, no museum admission required","url":"https://armyflying.com/"}],"pros":["Wallop Primary (Good, Ofsted May 2023) within a mile","Notable visitor attraction (Army Flying Museum) within the village","Wallop Brook chalk-stream walking route on the doorstep","Stockbridge, Salisbury and Andover all within 25 minutes by road"],"cons":["Operational helicopter activity from AAC airfield generates noise","A343 through-traffic, including military convoys at times","No mainline station within the village (Grateley 4.5 mi, Andover 7 mi)","Secondary catchment school rated Inadequate in 2022"],"whoItSuits":"Buyers comfortable with military aviation noise (AAC helicopters are a daily presence) in exchange for a Good village primary, museum-and-café amenity within the village, and a position equidistant between Andover, Stockbridge and Salisbury. Service families on Middle Wallop posting will find this the obvious choice; civilians attracted by chalk-stream walks and modest prices relative to Stockbridge proper will too. Less suited to those wanting absolute rural quiet or to families needing the catchment secondary school.","broadbandMedianMbps":null,"nearestStation":"Grateley (4.5 mi)","primarySupermarket":"Waitrose, Stockbridge (6.0 mi); Sainsbury''s, Andover (7.0 mi)","images":[],"sources":["https://en.wikipedia.org/wiki/Middle_Wallop","https://en.wikipedia.org/wiki/Army_Flying_Museum","https://armyflying.com/","https://armyflying.com/about-us/","https://files.ofsted.gov.uk/v1/file/50221039","https://www.wallop.hants.sch.uk/","https://www.thetrainline.com/train-times/andover-to-london-waterloo","https://www.testvalley.gov.uk/benefitsandcounciltax/counciltax/council-tax-charges"]},{"id":"middle-winterslow-sp5","name":"Middle Winterslow","village":"Middle Winterslow","town":"Salisbury","county":"Wiltshire","postcode":"SP5","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":50.98792,"lng":-1.86176},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"middle-woodford-sp4","name":"Middle Woodford","village":"Middle Woodford","town":"Salisbury","county":"Wiltshire","postcode":"SP4","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":51.16624,"lng":-1.77032},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"monkwood-gu34","name":"Monkwood","village":"Monkwood","town":"Petersfield","county":"Hampshire","postcode":"GU34","hubCity":"Guildford","regionDir":"","settlementType":"","subRegion":"Petersfield","coords":{"lat":51.13288,"lng":-0.96476},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"morestead-so21","name":"Morestead","village":"Morestead","town":"Winchester","county":"Hampshire","postcode":"SO21","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Winchester","coords":{"lat":51.08228,"lng":-1.29608},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":{"avgDetached":1058605,"avgSemi":541803,"avgTerraced":488613,"avgFlat":null,"asOf":"2026-05"},"councilTaxBand":null,"overview":"Morestead is a tiny former civil parish — now part of Owslebury parish — set on rising downland inside the South Downs National Park about three miles south-east of Winchester city centre. The historic parish covered around 1,701 acres and had just 96 residents at the 1931 census before being merged into Owslebury in 1932. The 12th-century parish church (no known dedication), with parts dating from around 1150 and a font from about 1200, sits at the lane junction at the heart of the hamlet, beside the former rectory built in the mid-1830s. The Roman road from Portchester to Winchester forms the main village street. Morestead is predominantly a farming community, with racehorse training stables, and is in the benefice of the South Downs Gateway Churches with Twyford, Owslebury and Colden Common. There is no shop, school or pub in the hamlet itself.","character":"Dispersed downland farming hamlet of fewer than thirty households: a parish church, a couple of working farms, the old rectory and a thin scatter of brick-and-flint cottages and 20th-century houses along Morestead Road and Fawley Lane. Strictly inside the South Downs National Park, so planning is tightly controlled.","amenities":["12th-century Parish Church (Morestead Hill)","Racehorse training stables within the parish","Nearest pub and shop: Twyford (1.5 mi) or Owslebury (1.7 mi)","Twyford St Mary''s CofE Primary School (1.6 mi) and village hall","Marwell Zoo (2 mi)","Full retail and GP at Winchester (3 mi)"],"schools":[{"name":"Twyford St Mary''s Church of England Primary School","phase":"Primary","type":"State (Voluntary Aided)","ofsted":"Good (2023)","distance":"1.6 mi","url":"https://reports.ofsted.gov.uk/provider/21/116307"},{"name":"Owslebury Primary School","phase":"Primary","type":"State (Community)","ofsted":"Good (2022)","distance":"1.7 mi","url":"https://reports.ofsted.gov.uk/provider/21/115934"},{"name":"Kings'' School, Winchester","phase":"Secondary","type":"State (Comprehensive)","ofsted":"Good (2023)","distance":"3.5 mi","url":"https://reports.ofsted.gov.uk/provider/23/136451"}],"transport":{"commutes":[{"to":"London Waterloo","time":"1h 4m (fastest) / 1h 23m (average)","mode":"drive to Winchester (3 mi) + direct train (SWR)","source":"https://www.thetrainline.com/train-times/winchester-to-london-waterloo"},{"to":"Southampton (by road)","time":"~25m","mode":"drive (B2177/M3 J11)","source":"https://www.google.com/maps"},{"to":"Winchester (by road)","time":"~10m","mode":"drive (B3404)","source":"https://www.google.com/maps"}],"nearestStation":"Winchester (3.0 mi)","roads":"B3404 (Morestead Road); B2177 ~1 mi; M3 J11 ~3 mi; A31 ~3 mi"},"prices":{"avgSold12Mo":712724,"avgDetached":1058605,"avgSemi":541803,"avgTerraced":488613,"avgBungalow":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/so21.html","asOf":"2026-05"},"thingsToDo":["Walking St Catherine''s Hill and Twyford Down (2 mi)","Marwell Zoo (2 mi)","South Downs National Park footpaths on the doorstep","Itchen Way along the river toward Winchester","Hinton Ampner gardens (National Trust, 5 mi)"],"placesToEat":[{"name":"The Phoenix, Twyford","type":"Village pub","notes":"1.5 mi north; full menu and rooms","url":"https://www.thephoenixtwyford.co.uk/"},{"name":"The Ship Inn, Owslebury","type":"Country pub with rooms","notes":"1.7 mi south-east in Owslebury","url":"https://whatpub.com/pubs/HAS/00337/ship-inn-owslebury"}],"pros":["Three miles to Winchester station and the direct Waterloo line","Inside the South Downs National Park — strong landscape protection","Two Good village primaries within 1.7 miles and a Good catchment secondary in Winchester","Twyford Down and Marwell Zoo both on the doorstep","Genuine farming-hamlet quiet, very few cars except local"],"cons":["No shop, pub or school in the hamlet itself — full car dependency","SO21 detached average over £1m; small market means listings are rare and dear","Single-track lanes are narrow and dim — winter driving is slower","National Park planning restricts development","Very limited public transport"],"whoItSuits":"Best for a buyer who wants National Park quiet within ten minutes of a mainline station and a market town, and accepts there are no facilities in the lane. For a solo £64k first-time buyer at £400k, freehold listings are typically out of reach in Morestead itself — the much larger village of Twyford (1.5 mi north, same SO21) has more terraced and semi stock and gives you a Good primary, pubs and a station within walking distance, with Owslebury (1.7 mi) cheaper still for the same downs setting. If you''d rather chase budget than National Park status, Colden Common (3 mi south) is the obvious next stop.","broadbandMedianMbps":null,"nearestStation":"Winchester (3.0 mi)","primarySupermarket":"Sainsbury''s, Middle Brook Street, Winchester (3.0 mi); Co-op, Twyford (1.5 mi)","images":[],"sources":[{"title":"Wikipedia — Morestead","url":"https://en.wikipedia.org/wiki/Morestead"},{"title":"British History Online — Parishes: Morestead","url":"https://www.british-history.ac.uk/vch/hants/vol3/pp329-330"},{"title":"South Downs Gateway Churches","url":"https://www.sdgateway.org.uk/"},{"title":"Ofsted — Owslebury Primary School","url":"https://reports.ofsted.gov.uk/provider/21/115934"},{"title":"Rightmove — SO21 house prices","url":"https://www.rightmove.co.uk/house-prices/so21.html"},{"title":"Trainline — Winchester to London Waterloo","url":"https://www.thetrainline.com/train-times/winchester-to-london-waterloo"}]},{"id":"nether-wallop-so20","name":"Nether Wallop","village":"Nether Wallop","town":"Stockbridge","county":"Hampshire","postcode":"SO20","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Stockbridge","coords":{"lat":51.137,"lng":-1.47992},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"netherhampton-sp2","name":"Netherhampton","village":"Netherhampton","town":"Salisbury","county":"Wiltshire","postcode":"SP2","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":51.07336,"lng":-1.85416},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]}]'::jsonb) AS value
